def format_tool_specs_for_prompt(tool_names: List[str] | None = None) -> str:
    """
    Convert tool specs into a readable manual for the LLM executor prompt.
    """
    selected = TOOL_SPECS

    if tool_names:
        selected = {
            name: spec
            for name, spec in TOOL_SPECS.items()
            if name in tool_names
        }

    blocks = []

    for name, spec in selected.items():
        params = spec.get("parameters", {})
        when_to_use = spec.get("when_to_use", [])
        when_not_to_use = spec.get("when_not_to_use", [])

        block = [
            f"Tool: {name}",
            f"Description: {spec.get('description', '')}",
            "When to use:",
        ]

        for item in when_to_use:
            block.append(f"- {item}")

        if when_not_to_use:
            block.append("When not to use:")
            for item in when_not_to_use:
                block.append(f"- {item}")

        block.append("Parameters:")
        if params:
            for param_name, param_spec in params.items():
                required = param_spec.get("required", False)
                default = param_spec.get("default", None)
                desc = param_spec.get("description", "")
                type_name = param_spec.get("type", "unknown")

                req_text = "required" if required else f"default={default}"
                block.append(
                    f"- {param_name}: {type_name}, {req_text}. {desc}"
                )
        else:
            block.append("- No parameters.")

        block.append(f"Output: {spec.get('output', '')}")

        blocks.append("\n".join(block))

    return "\n\n".join(blocks)

def _safe_path(state: AgentState, relative_path: str) -> Path:
    """
    Resolve a path safely inside repo root.
    """
    return state.repo_path(relative_path)

def _is_probably_text_file(path: Path) -> bool:
    if path.suffix.lower() in TEXT_FILE_EXTENSIONS:
        return True

    if path.name in {
        "Dockerfile",
        "Makefile",
        "requirements.txt",
        ".gitignore",
        ".env.example",
    }:
        return True

    return False

def list_files(
    state: AgentState,
    directory: str = ".",
    max_depth: int = 3,
    include_hidden: bool = False,
) -> ToolResult:
    """
    List files under a repository directory.
    """
    try:
        base = _safe_path(state, directory)

        if not base.exists():
            return ToolResult(
                tool_name="list_files",
                success=False,
                output="",
                error=f"Directory does not exist: {directory}",
            )

        if not base.is_dir():
            return ToolResult(
                tool_name="list_files",
                success=False,
                output="",
                error=f"Path is not a directory: {directory}",
            )

        root = Path(state.repo_root).resolve()
        lines: List[str] = []

        def walk(current: Path, depth: int) -> None:
            if depth > max_depth:
                return

            try:
                children = sorted(
                    current.iterdir(),
                    key=lambda p: (not p.is_dir(), p.name.lower()),
                )
            except PermissionError:
                return

            for child in children:
                rel = child.relative_to(root)

                if _should_ignore(rel):
                    continue

                if not include_hidden and _is_hidden(rel):
                    continue

                indent = "  " * depth
                suffix = "/" if child.is_dir() else ""
                lines.append(f"{indent}{rel}{suffix}")

                if child.is_dir():
                    walk(child, depth + 1)

        walk(base, 0)

        output = "\n".join(lines) if lines else "(empty directory)"

        return ToolResult(
            tool_name="list_files",
            success=True,
            output=output,
            metadata={
                "directory": directory,
                "max_depth": max_depth,
            },
        )

    except Exception as exc:
        return ToolResult(
            tool_name="list_files",
            success=False,
            output="",
            error=f"{type(exc).__name__}: {exc}",
        )

def read_file(
    state: AgentState,
    path: str,
    start_line: Optional[int] = None,
    end_line: Optional[int] = None,
) -> ToolResult:
    """
    Read a repository file with optional line range.
    """
    try:
        target = _safe_path(state, path)

        if not target.exists():
            return ToolResult(
                tool_name="read_file",
                success=False,
                output="",
                error=f"File does not exist: {path}",
                metadata={"path": path},
            )

        if not target.is_file():
            return ToolResult(
                tool_name="read_file",
                success=False,
                output="",
                error=f"Path is not a file: {path}",
                metadata={"path": path},
            )

        if not _is_probably_text_file(target):
            return ToolResult(
                tool_name="read_file",
                success=False,
                output="",
                error=f"File does not look like a supported text/code file: {path}",
                metadata={"path": path},
            )

        content = _read_text_file(target)
        lines = content.splitlines()

        total_lines = len(lines)

        if start_line is None:
            start_line = 1

        if end_line is None:
            end_line = total_lines

        start_line = max(1, int(start_line))
        end_line = min(total_lines, int(end_line))

        if start_line > end_line:
            return ToolResult(
                tool_name="read_file",
                success=False,
                output="",
                error=f"Invalid line range: {start_line}-{end_line}",
                metadata={"path": path},
            )

        selected = lines[start_line - 1:end_line]

        numbered = [
            f"{line_no:>4}: {line}"
            for line_no, line in enumerate(selected, start=start_line)
        ]

        output = "\n".join(numbered)

        return ToolResult(
            tool_name="read_file",
            success=True,
            output=output,
            metadata={
                "path": path,
                "start_line": start_line,
                "end_line": end_line,
                "total_lines": total_lines,
            },
        )

    except Exception as exc:
        return ToolResult(
            tool_name="read_file",
            success=False,
            output="",
            error=f"{type(exc).__name__}: {exc}",
            metadata={"path": path},
        )

def search_code(
    state: AgentState,
    query: str,
    include_glob: str = "*.py",
    max_results: int = 50,
    use_regex: bool = False,
) -> ToolResult:
    """
    Search repository files using keyword or regex.
    """
    try:
        root = Path(state.repo_root).resolve()

        if not query or not query.strip():
            return ToolResult(
                tool_name="search_code",
                success=False,
                output="",
                error="Empty query.",
            )

        matches: List[str] = []
        pattern = re.compile(query) if use_regex else None

        for file_path in root.rglob("*"):
            if len(matches) >= max_results:
                break

            if not file_path.is_file():
                continue

            rel = file_path.relative_to(root)

            if _should_ignore(rel):
                continue

            if _is_hidden(rel):
                continue

            if include_glob and not fnmatch.fnmatch(str(rel), include_glob):
                continue

            if not _is_probably_text_file(file_path):
                continue

            try:
                lines = _read_text_file(file_path).splitlines()
            except Exception:
                continue

            for line_no, line in enumerate(lines, start=1):
                if use_regex:
                    found = bool(pattern.search(line))
                else:
                    found = query.lower() in line.lower()

                if found:
                    matches.append(f"{rel}:{line_no}: {line.strip()}")

                    if len(matches) >= max_results:
                        break

        output = "\n".join(matches) if matches else "No matches found."

        return ToolResult(
            tool_name="search_code",
            success=True,
            output=output,
            metadata={
                "query": query,
                "include_glob": include_glob,
                "max_results": max_results,
                "num_matches": len(matches),
                "use_regex": use_regex,
            },
        )

    except re.error as exc:
        return ToolResult(
            tool_name="search_code",
            success=False,
            output="",
            error=f"Invalid regex: {exc}",
            metadata={"query": query},
        )

    except Exception as exc:
        return ToolResult(
            tool_name="search_code",
            success=False,
            output="",
            error=f"{type(exc).__name__}: {exc}",
            metadata={"query": query},
        )

def write_file(
    state: AgentState,
    path: str,
    content: str,
    overwrite: bool = False,
) -> ToolResult:
    """
    Write full content to a file.
    """
    try:
        target = _safe_path(state, path)

        if target.exists() and not overwrite:
            return ToolResult(
                tool_name="write_file",
                success=False,
                output="",
                error=f"File already exists and overwrite=False: {path}",
                metadata={"path": path},
            )

        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(content, encoding="utf-8")

        return ToolResult(
            tool_name="write_file",
            success=True,
            output=f"Wrote file: {path}",
            metadata={
                "path": path,
                "changed_files": [path],
                "num_chars": len(content),
            },
        )

    except Exception as exc:
        return ToolResult(
            tool_name="write_file",
            success=False,
            output="",
            error=f"{type(exc).__name__}: {exc}",
            metadata={"path": path},
        )

def replace_in_file(
    state: AgentState,
    path: str,
    old_text: str,
    new_text: str,
    replace_all: bool = False,
) -> ToolResult:
    """
    Replace exact text inside a file.
    """
    try:
        target = _safe_path(state, path)

        if not target.exists() or not target.is_file():
            return ToolResult(
                tool_name="replace_in_file",
                success=False,
                output="",
                error=f"File does not exist: {path}",
                metadata={"path": path},
            )

        content = _read_text_file(target)

        if old_text not in content:
            return ToolResult(
                tool_name="replace_in_file",
                success=False,
                output="",
                error="old_text not found in file.",
                metadata={"path": path},
            )

        count = content.count(old_text)

        if replace_all:
            new_content = content.replace(old_text, new_text)
            replaced = count
        else:
            new_content = content.replace(old_text, new_text, 1)
            replaced = 1

        target.write_text(new_content, encoding="utf-8")

        return ToolResult(
            tool_name="replace_in_file",
            success=True,
            output=f"Updated {path}. Replacements made: {replaced}",
            metadata={
                "path": path,
                "changed_files": [path],
                "replacements": replaced,
                "total_occurrences": count,
            },
        )

    except Exception as exc:
        return ToolResult(
            tool_name="replace_in_file",
            success=False,
            output="",
            error=f"{type(exc).__name__}: {exc}",
            metadata={"path": path},
        )

def apply_patch(
    state: AgentState,
    patch: str,
) -> ToolResult:
    """
    Apply a unified diff patch using git apply.
    """
    try:
        if not patch or not patch.strip():
            return ToolResult(
                tool_name="apply_patch",
                success=False,
                output="",
                error="Empty patch.",
            )

        root = Path(state.repo_root).resolve()

        changed_files = _extract_changed_files_from_patch(patch)

        with tempfile.NamedTemporaryFile(
            mode="w",
            suffix=".patch",
            delete=False,
            encoding="utf-8",
        ) as tmp:
            tmp.write(patch)
            patch_path = tmp.name

        try:
            check_cmd = ["git", "apply", "--check", patch_path]
            check_proc = subprocess.run(
                check_cmd,
                cwd=root,
                capture_output=True,
                text=True,
                timeout=30,
            )

            if check_proc.returncode != 0:
                return ToolResult(
                    tool_name="apply_patch",
                    success=False,
                    output=check_proc.stdout,
                    error=check_proc.stderr or "git apply --check failed.",
                    metadata={"changed_files": changed_files},
                )

            apply_cmd = ["git", "apply", patch_path]
            apply_proc = subprocess.run(
                apply_cmd,
                cwd=root,
                capture_output=True,
                text=True,
                timeout=30,
            )

            if apply_proc.returncode != 0:
                return ToolResult(
                    tool_name="apply_patch",
                    success=False,
                    output=apply_proc.stdout,
                    error=apply_proc.stderr or "git apply failed.",
                    metadata={"changed_files": changed_files},
                )

            return ToolResult(
                tool_name="apply_patch",
                success=True,
                output="Patch applied successfully.",
                metadata={"changed_files": changed_files},
            )

        finally:
            try:
                os.remove(patch_path)
            except OSError:
                pass

    except subprocess.TimeoutExpired:
        return ToolResult(
            tool_name="apply_patch",
            success=False,
            output="",
            error="Patch command timed out.",
        )

    except Exception as exc:
        return ToolResult(
            tool_name="apply_patch",
            success=False,
            output="",
            error=f"{type(exc).__name__}: {exc}",
        )

def run_command(
    state: AgentState,
    command: str,
    timeout: int = 60,
) -> ToolResult:
    """
    Run a safe shell command inside the repository.
    """
    try:
        safety_error = _validate_command_safety(command)

        if safety_error:
            return ToolResult(
                tool_name="run_command",
                success=False,
                output="",
                error=safety_error,
                metadata={"command": command},
            )

        root = Path(state.repo_root).resolve()

        proc = subprocess.run(
            command,
            cwd=root,
            shell=True,
            capture_output=True,
            text=True,
            timeout=timeout,
        )

        output = _format_command_output(proc.stdout, proc.stderr, proc.returncode)

        return ToolResult(
            tool_name="run_command",
            success=proc.returncode == 0,
            output=output,
            error=None if proc.returncode == 0 else proc.stderr,
            metadata={
                "command": command,
                "exit_code": proc.returncode,
                "stdout": proc.stdout,
                "stderr": proc.stderr,
            },
        )

    except subprocess.TimeoutExpired:
        return ToolResult(
            tool_name="run_command",
            success=False,
            output="",
            error=f"Command timed out after {timeout} seconds.",
            metadata={"command": command, "timeout": timeout},
        )

    except Exception as exc:
        return ToolResult(
            tool_name="run_command",
            success=False,
            output="",
            error=f"{type(exc).__name__}: {exc}",
            metadata={"command": command},
        )

def identify_error(
    state: AgentState,
    error_log: str,
) -> ToolResult:
    """
    Heuristically analyze an error log.
    """
    try:
        if not error_log or not error_log.strip():
            return ToolResult(
                tool_name="identify_error",
                success=False,
                output="",
                error="Empty error_log.",
            )

        analysis = {
            "error_type": "Unknown",
            "likely_root_cause": "Could not determine from heuristics.",
            "relevant_files": [],
            "suggested_next_steps": [],
        }

        text = error_log

        if "ModuleNotFoundError" in text:
            analysis["error_type"] = "ModuleNotFoundError"
            analysis["likely_root_cause"] = (
                "A module import path is wrong, missing, or not installed."
            )
            analysis["suggested_next_steps"] = [
                "Search for the missing module name.",
                "Check package/file names.",
                "Check relative imports and __init__.py files.",
            ]

        elif "ImportError" in text:
            analysis["error_type"] = "ImportError"
            analysis["likely_root_cause"] = (
                "A symbol cannot be imported from the target module."
            )
            analysis["suggested_next_steps"] = [
                "Search for the imported symbol.",
                "Check whether the function/class is defined.",
                "Check filename mismatch such as tool.py vs tools.py.",
            ]

        elif "NameError" in text:
            analysis["error_type"] = "NameError"
            analysis["likely_root_cause"] = (
                "A variable, function, or class is referenced before definition."
            )
            analysis["suggested_next_steps"] = [
                "Search for the missing name.",
                "Check scope and imports.",
            ]

        elif "AttributeError" in text:
            analysis["error_type"] = "AttributeError"
            analysis["likely_root_cause"] = (
                "An object does not have the referenced method or attribute."
            )
            analysis["suggested_next_steps"] = [
                "Check class definition.",
                "Check method name mismatch.",
                "Check whether the object type is correct.",
            ]

        elif "TypeError" in text:
            analysis["error_type"] = "TypeError"
            analysis["likely_root_cause"] = (
                "Function arguments or object types do not match expected usage."
            )
            analysis["suggested_next_steps"] = [
                "Check function signatures.",
                "Check constructor parameters.",
                "Check call sites.",
            ]

        elif "SyntaxError" in text:
            analysis["error_type"] = "SyntaxError"
            analysis["likely_root_cause"] = "Python syntax is invalid."
            analysis["suggested_next_steps"] = [
                "Open the file and line reported by the traceback.",
                "Fix syntax before running tests again.",
            ]

        file_matches = re.findall(r'File "([^"]+)", line (\d+)', text)
        relevant_files = []

        for file_path, line_no in file_matches:
            try:
                p = Path(file_path)
                if p.is_absolute():
                    rel = str(p.relative_to(Path(state.repo_root).resolve()))
                else:
                    rel = file_path
            except Exception:
                rel = file_path

            relevant_files.append(f"{rel}:{line_no}")

        analysis["relevant_files"] = relevant_files

        output = (
            f"Error type: {analysis['error_type']}\n"
            f"Likely root cause: {analysis['likely_root_cause']}\n"
            f"Relevant files:\n"
            + "\n".join(f"- {f}" for f in analysis["relevant_files"])
            + "\nSuggested next steps:\n"
            + "\n".join(f"- {s}" for s in analysis["suggested_next_steps"])
        )

        return ToolResult(
            tool_name="identify_error",
            success=True,
            output=output,
            metadata=analysis,
        )

    except Exception as exc:
        return ToolResult(
            tool_name="identify_error",
            success=False,
            output="",
            error=f"{type(exc).__name__}: {exc}",
        )

def retrieve_context(
    state: AgentState,
    query: str,
    top_k: int = 6,
    force_rebuild: bool = False,
) -> ToolResult:
    """
    Retrieve relevant repository context using FAISS-based RAG.
    """
    try:
        from rag.retrieve import RAGEngine

        engine = RAGEngine(
            repo_root=state.repo_root,
            index_dir=".agent_index",
            auto_load=True,
        )

        if force_rebuild:
            engine.rebuild()

        results = engine.retrieve(
            query=query,
            top_k=top_k,
            vector_top_k=max(12, top_k * 2),
            keyword_top_k=max(20, top_k * 3),
        )

        context_text = engine.format_context(results)

        # Store structured context into state.
        state.retrieved_context = results

        return ToolResult(
            tool_name="retrieve_context",
            success=True,
            output=context_text,
            metadata={
                "query": query,
                "top_k": top_k,
                "num_results": len(results),
                "index_dir": ".agent_index",
            },
        )

    except Exception as exc:
        return ToolResult(
            tool_name="retrieve_context",
            success=False,
            output="",
            error=f"{type(exc).__name__}: {exc}",
            metadata={
                "query": query,
                "top_k": top_k,
            },
        )

def execute_tool_call(
    state: AgentState,
    tool_name: str,
    arguments: Optional[Dict[str, Any]] = None,
) -> ToolResult:
    """
    Optional compatibility helper.
    Useful if your executor wants a single execute_tool_call entrypoint.
    """
    arguments = arguments or {}
    tool_map = get_tool_map()

    if tool_name not in tool_map:
        return ToolResult(
            tool_name=tool_name,
            success=False,
            output="",
            error=f"Unknown tool: {tool_name}",
        )

    return tool_map[tool_name](state=state, **arguments)

def _validate_command_safety(command: str) -> Optional[str]:
    if not command or not command.strip():
        return "Empty command."

    for pattern in DANGEROUS_COMMAND_PATTERNS:
        if re.search(pattern, command):
            return f"Blocked dangerous command pattern: {pattern}"

    return None

def _extract_changed_files_from_patch(patch: str) -> List[str]:
    changed = []

    for line in patch.splitlines():
        if line.startswith("+++ b/"):
            changed.append(line.replace("+++ b/", "").strip())
        elif line.startswith("--- a/"):
            file_path = line.replace("--- a/", "").strip()
            if file_path not in changed and file_path != "/dev/null":
                changed.append(file_path)

    return sorted(set(changed))

class Planner:
    """
    Planner decomposes the user's task into executable coding-agent steps.

    It can work with:
    - an LLM client that has .chat(messages)
    - or fallback rule-based planning if no client is passed.
    """

    def __init__(self, client: Optional[Any] = None):
        self.client = client

    def create_initial_plan(self, state: AgentState) -> List[PlanStep]:
        if self.client is None:
            steps = self._fallback_plan(state.input_query)
            state.add_plan(steps)
            return steps

        prompt = self._build_initial_plan_prompt(state)

        response = self.client.chat([
            {"role": "system", "content": self._system_prompt()},
            {"role": "user", "content": prompt},
        ])

        content = self._normalize_llm_response(response)
        steps = self._parse_plan(content)

        if not steps:
            steps = self._fallback_plan(state.input_query)

        state.add_plan(steps)
        return steps

    def adjust_plan(self, state: AgentState) -> List[PlanStep]:
        """
        Re-plan based on recent errors and tool results.
        """
        if self.client is None:
            return self._fallback_replan(state)

        prompt = self._build_replan_prompt(state)

        response = self.client.chat([
            {"role": "system", "content": self._system_prompt()},
            {"role": "user", "content": prompt},
        ])

        content = self._normalize_llm_response(response)
        new_steps = self._parse_plan(content)

        if not new_steps:
            new_steps = self._fallback_replan(state)

        next_id = max([s.step_id for s in state.plan], default=0) + 1

        for i, step in enumerate(new_steps):
            step.step_id = next_id + i

        state.plan.extend(new_steps)
        return state.plan

    def _system_prompt(self) -> str:
        return """
You are a senior planner for a coding agent.

Your job:
- Break the user request into concrete coding steps.
- Each step should be executable by tools.
- Prefer repository inspection before code edits.
- Always include validation after edits.

Return only valid JSON.

Schema:
[
  {
    "task": "Clear task description",
    "expected_output": "What should be produced by this step",
    "suggested_tools": ["list_files", "search_code", "read_file"]
  }
]
""".strip()

    def _build_initial_plan_prompt(self, state: AgentState) -> str:
        return f"""
User request:
{state.input_query}

Repository root:
{state.repo_root}

Create a short execution plan for a coding agent.

Rules:
1. First understand the repository structure.
2. Use search_code or retrieve_context before editing.
3. Read relevant files before patching.
4. Run tests or syntax checks after code changes.
5. Keep the plan practical and executable.
6. Return only JSON.
""".strip()

    def _build_replan_prompt(self, state: AgentState) -> str:
        return f"""
The coding agent needs to re-plan.

Original user request:
{state.input_query}

Current plan:
{state.plan_summary()}

Recent tool results:
{state.recent_tool_summary()}

Errors seen:
{state.errors_seen}

Files read:
{state.files_read}

Files modified:
{state.files_modified}

Create a new short plan to recover from the current failure.

Rules:
1. Focus only on unresolved or failed parts.
2. Use error logs to identify the root cause.
3. Suggest specific tools.
4. Include validation.
5. Return only JSON.
""".strip()

    def _normalize_llm_response(self, response: Any) -> str:
        """
        Makes this planner compatible with different LLM clients.
        """
        if isinstance(response, str):
            return response

        if isinstance(response, dict):
            if "content" in response:
                return str(response["content"])

            if "message" in response and isinstance(response["message"], dict):
                return str(response["message"].get("content", ""))

            if "choices" in response:
                try:
                    return response["choices"][0]["message"]["content"]
                except Exception:
                    return str(response)

        return str(response)

    def _parse_plan(self, content: str) -> List[PlanStep]:
        try:
            data = json.loads(content)
        except json.JSONDecodeError:
            data = self._extract_json_array(content)

        if not isinstance(data, list):
            return []

        steps = []

        for idx, item in enumerate(data, start=1):
            if isinstance(item, str):
                steps.append(
                    PlanStep(
                        step_id=idx,
                        task=item,
                        expected_output="Complete this step.",
                        suggested_tools=[],
                    )
                )
                continue

            if not isinstance(item, dict):
                continue

            task = item.get("task") or item.get("description")
            if not task:
                continue

            suggested_tools = item.get("suggested_tools", [])
            if isinstance(suggested_tools, str):
                suggested_tools = [suggested_tools]

            steps.append(
                PlanStep(
                    step_id=idx,
                    task=task,
                    expected_output=item.get("expected_output", ""),
                    suggested_tools=suggested_tools,
                    status=StepStatus.PENDING,
                )
            )

        return steps

    def _extract_json_array(self, text: str) -> Any:
        """
        Extract JSON array from LLM output if it contains extra text.
        """
        match = re.search(r"\[[\s\S]*\]", text)
        if not match:
            return None

        try:
            return json.loads(match.group(0))
        except json.JSONDecodeError:
            return None

    def _fallback_plan(self, user_query: str) -> List[PlanStep]:
        """
        Deterministic default plan. Useful before the LLM client is fully stable.
        """
        return [
            PlanStep(
                step_id=1,
                task="Inspect the repository structure to understand the project layout.",
                expected_output="A concise summary of the repo structure.",
                suggested_tools=["list_files"],
            ),
            PlanStep(
                step_id=2,
                task=f"Search the codebase for files relevant to the user request: {user_query}",
                expected_output="A list of relevant files and symbols.",
                suggested_tools=["search_code", "retrieve_context"],
            ),
            PlanStep(
                step_id=3,
                task="Read the most relevant files and identify the implementation gap.",
                expected_output="A diagnosis of what needs to be changed.",
                suggested_tools=["read_file"],
            ),
            PlanStep(
                step_id=4,
                task="Apply a minimal code change to address the issue.",
                expected_output="A focused patch.",
                suggested_tools=["apply_patch", "replace_in_file"],
            ),
            PlanStep(
                step_id=5,
                task="Run validation using tests or syntax checks.",
                expected_output="Test or validation result.",
                suggested_tools=["run_tests", "run_command"],
            ),
        ]

    def _fallback_replan(self, state: AgentState) -> List[PlanStep]:
        return [
            PlanStep(
                step_id=1,
                task="Analyze the latest error or failed tool result.",
                expected_output="Root cause of the failure.",
                suggested_tools=["identify_error", "search_code"],
            ),
            PlanStep(
                step_id=2,
                task="Read the files most likely related to the failure.",
                expected_output="Relevant code context.",
                suggested_tools=["read_file", "retrieve_context"],
            ),
            PlanStep(
                step_id=3,
                task="Apply a small corrective patch.",
                expected_output="Patch that addresses the failure.",
                suggested_tools=["apply_patch"],
            ),
            PlanStep(
                step_id=4,
                task="Run validation again.",
                expected_output="Passing tests or clear remaining error.",
                suggested_tools=["run_tests"],
            ),
        ]

def adjust_plan(self, state: AgentState) -> List[PlanStep]:
    """
    Re-plan based on recent errors and tool results.
    """
    if self.client is None:
        return self._fallback_replan(state)

    prompt = self._build_replan_prompt(state)

    response = self.client.chat([
        {"role": "system", "content": self._system_prompt()},
        {"role": "user", "content": prompt},
    ])

    content = self._normalize_llm_response(response)
    new_steps = self._parse_plan(content)

    if not new_steps:
        new_steps = self._fallback_replan(state)

    next_id = max([s.step_id for s in state.plan], default=0) + 1

    for i, step in enumerate(new_steps):
        step.step_id = next_id + i

    state.plan.extend(new_steps)
    return state.plan

    def _build_replan_prompt(self, state: AgentState) -> str:
        return f"""
The coding agent needs to re-plan.

Original user request:
{state.input_query}

Current plan:
{state.plan_summary()}

Recent tool results:
{state.recent_tool_summary()}

Errors seen:
{state.errors_seen}

Files read:
{state.files_read}

Files modified:
{state.files_modified}

Create a new short plan to recover from the current failure.

Rules:
1. Focus only on unresolved or failed parts.
2. Use error logs to identify the root cause.
3. Suggest specific tools.
4. Include validation.
5. Return only JSON.
""".strip()

def _normalize_llm_response(self, response: Any) -> str:
    """
    Makes this planner compatible with different LLM clients.
    """
    if isinstance(response, str):
        return response

    if isinstance(response, dict):
        if "content" in response:
            return str(response["content"])

        if "message" in response and isinstance(response["message"], dict):
            return str(response["message"].get("content", ""))

        if "choices" in response:
            try:
                return response["choices"][0]["message"]["content"]
            except Exception:
                return str(response)

    return str(response)

def _parse_plan(self, content: str) -> List[PlanStep]:
    try:
        data = json.loads(content)
    except json.JSONDecodeError:
        data = self._extract_json_array(content)

    if not isinstance(data, list):
