def add_tool_result(self, result: ToolResult) -> None:
    self.short_term.append(result)

    if len(self.short_term) > self.short_term_limit:
        self.short_term = self.short_term[-self.short_term_limit:]

def summarize_short_term(self, max_items: int = 8, max_chars: int = 4000) -> str:
    recent = self.short_term[-max_items:]

    if not recent:
        return "No recent tool results."

    blocks = []
    for item in recent:
        blocks.append(item.to_text(max_chars=800))

    text = "\n\n".join(blocks)
    if len(text) > max_chars:
        text = text[:max_chars] + "\n...[truncated]"
    return text

def summarize_long_term(self, max_items: int = 8, max_chars: int = 4000) -> str:
    if not self.long_term:
        return "No long-term memory yet."

    recent = self.long_term[-max_items:]
    lines = []

    for item in recent:
        source = f" Source: {item.source}." if item.source else ""
        lines.append(f"- [{item.memory_type}] {item.content}{source}")

    text = "\n".join(lines)
    if len(text) > max_chars:
        text = text[:max_chars] + "\n...[truncated]"
    return text

def get_context(self) -> str:
    return (
        "Short-term memory:\n"
        f"{self.summarize_short_term()}\n\n"
        "Long-term memory:\n"
        f"{self.summarize_long_term()}"
    )

def extract_insight_from_tool_result(self, result: ToolResult) -> Optional[str]:
    """
    A simple rule-based insight extractor.
    Later, this can be replaced by an LLM summarizer.
    """
    if not result.success and result.error:
        return f"Tool {result.tool_name} failed with error: {result.error}"

    if result.tool_name == "read_file" and result.success:
        path = result.metadata.get("path")
        if path:
            return f"Read file {path}; it may be relevant to the current task."

    if result.tool_name == "run_tests":
        if result.success:
            return "Tests passed after the latest execution."
        return "Tests failed; inspect traceback and relevant files before editing again."

    return None

def update_from_tool_result(self, result: ToolResult) -> None:
    self.add_tool_result(result)

    insight = self.extract_insight_from_tool_result(result)
    if insight:
        self.add_insight(
            insight=insight,
            memory_type="tool_observation",
            source=result.tool_name,
            metadata=result.metadata,
        )

class Executor:
    """
    Executor runs one plan step at a time.

    Main responsibilities:
    - Build context from state, memory, and RAG.
    - Ask LLM which tool to call.
    - Execute the selected tool.
    - Store tool results.
    - Mark step completed or failed.
    """

    def __init__(
        self,
        client: Optional[Any] = None,
        tools: Optional[Dict[str, Any]] = None,
        memory: Optional[AgentMemory] = None,
        max_tool_rounds: int = 4,
    ):
        self.client = client
        self.tools = tools or {}
        self.memory = memory or AgentMemory()
        self.max_tool_rounds = max_tool_rounds

    def execute_current_step(self, state: AgentState) -> AgentState:
        current_step = state.get_current_step()

        if current_step is None:
            state.is_finished = True
            state.final_answer = self._build_final_answer(state)
            return state

        current_step.mark_running()

        try:
            if self.client is None:
                result_text = self._fallback_execute_step(current_step, state)
            else:
                result_text = self._llm_execute_step(current_step, state)

            current_step.mark_completed(result_text)
            state.add_history(
                f"Step {current_step.step_id} completed: {current_step.task}\n{result_text}"
            )

        except Exception as exc:
            error = f"{type(exc).__name__}: {str(exc)}\n{traceback.format_exc()}"
            current_step.mark_failed(error)
            state.errors_seen.append(error)
            state.add_history(
                f"Step {current_step.step_id} failed: {current_step.task}\n{error}"
            )

        return state

    def run_step(self, step: PlanStep, state: AgentState) -> ToolResult:
        """
        Compatibility wrapper if main.py calls executor.run_step(step, state).
        """
        step.mark_running()

        try:
            if self.client is None:
                output = self._fallback_execute_step(step, state)
            else:
                output = self._llm_execute_step(step, state)

            step.mark_completed(output)

            result = ToolResult(
                tool_name="executor",
                success=True,
                output=output,
                metadata={"step_id": step.step_id, "task": step.task},
            )

        except Exception as exc:
            error = f"{type(exc).__name__}: {str(exc)}"
            step.mark_failed(error)

            result = ToolResult(
                tool_name="executor",
                success=False,
                output="",
                error=error,
                metadata={"step_id": step.step_id, "task": step.task},
            )

        state.add_tool_result(result)
        self.memory.update_from_tool_result(result)
        return result

    def _llm_execute_step(self, step: PlanStep, state: AgentState) -> str:
        messages = self._build_messages(step, state)

        final_outputs = []

        for round_idx in range(self.max_tool_rounds):
            response = self.client.chat(messages)
            content = self._normalize_llm_response(response)

            tool_call = self._parse_tool_call(content)

            if tool_call is None:
                final_outputs.append(content)
                break

            tool_name = tool_call.get("tool_name")
            arguments = tool_call.get("arguments", {})

            tool_result = self._execute_tool(tool_name, arguments, state)

            step.tool_results.append(tool_result)
            state.add_tool_result(tool_result)
            self.memory.update_from_tool_result(tool_result)

            messages.append({
                "role": "assistant",
                "content": content,
            })
            messages.append({
                "role": "tool",
                "content": tool_result.to_text(),
            })

            final_outputs.append(tool_result.to_text(max_chars=1500))

            if self._tool_result_is_enough(step, tool_result):
                break

        if not final_outputs:
            return "No output produced."

        return "\n\n".join(final_outputs)

    def _fallback_execute_step(self, step: PlanStep, state: AgentState) -> str:
        """
        Rule-based execution before the LLM tool-calling layer is stable.
        """
        outputs = []

        tools_to_try = step.suggested_tools or []

        if not tools_to_try:
            task_lower = step.task.lower()

            if "structure" in task_lower or "layout" in task_lower:
                tools_to_try = ["list_files"]
            elif "search" in task_lower:
                tools_to_try = ["search_code"]
            elif "read" in task_lower:
                tools_to_try = ["read_file"]
            elif "test" in task_lower or "validation" in task_lower:
                tools_to_try = ["run_tests"]
            else:
                tools_to_try = ["retrieve_context"]

        for tool_name in tools_to_try:
            if tool_name not in self.tools:
                outputs.append(f"Tool {tool_name} is not available.")
                continue

            arguments = self._build_fallback_arguments(tool_name, step, state)
            tool_result = self._execute_tool(tool_name, arguments, state)

            step.tool_results.append(tool_result)
            state.add_tool_result(tool_result)
            self.memory.update_from_tool_result(tool_result)

            outputs.append(tool_result.to_text())

            if tool_result.success:
                break

        return "\n\n".join(outputs)

    def _build_fallback_arguments(
        self,
        tool_name: str,
        step: PlanStep,
        state: AgentState,
    ) -> Dict[str, Any]:
        if tool_name == "list_files":
            return {
                "directory": ".",
                "max_depth": 3,
            }

        if tool_name == "search_code":
            return {
                "query": state.input_query,
                "include_glob": "*.py",
            }

        if tool_name == "retrieve_context":
            return {
                "query": f"{state.input_query}\nCurrent step: {step.task}",
                "top_k": 6,
            }

        if tool_name == "run_tests":
            return {
                "test_path": None,
                "timeout": 60,
            }

        if tool_name == "read_file":
            # If fallback does not know a file, try main.py first.
            return {
                "path": "main.py",
                "start_line": None,
                "end_line": None,
            }

        return {}

    def _execute_tool(
        self,
        tool_name: str,
        arguments: Dict[str, Any],
        state: AgentState,
    ) -> ToolResult:
        if tool_name not in self.tools:
            return ToolResult(
                tool_name=tool_name or "unknown",
                success=False,
                output="",
                error=f"Tool not found: {tool_name}",
            )

        tool_fn = self.tools[tool_name]

        try:
            result = tool_fn(state=state, **arguments)

            if isinstance(result, ToolResult):
                return result

            if isinstance(result, dict):
                return ToolResult(
                    tool_name=tool_name,
                    success=bool(result.get("success", True)),
                    output=str(result.get("output", "")),
                    error=result.get("error"),
                    metadata=result.get("metadata", {}),
                )

            return ToolResult(
                tool_name=tool_name,
                success=True,
                output=str(result),
            )

        except Exception as exc:
            return ToolResult(
                tool_name=tool_name,
                success=False,
                output="",
                error=f"{type(exc).__name__}: {str(exc)}",
            )

    def _build_messages(self, step: PlanStep, state: AgentState) -> List[Dict[str, str]]:
        system_prompt = self._system_prompt()

        user_prompt = f"""
User request:
{state.input_query}

Current plan:
{state.plan_summary()}

Current step:
Step {step.step_id}: {step.task}

Expected output:
{step.expected_output}

Suggested tools:
{step.suggested_tools}

Retrieved context:
{state.retrieved_context_text()}

Memory:
{self.memory.get_context()}

Recent tool results:
{state.recent_tool_summary()}

Available tools:
{self._tool_descriptions()}

Instructions:
- Decide whether you need to call a tool.
- If you need a tool, return only JSON with this schema:
  {{
    "tool_name": "tool_name_here",
    "arguments": {{
      "key": "value"
    }}
  }}
- If the step is complete, return a concise final message.
- Do not invent file contents.
- Read files before editing them.
- Run validation after applying code changes.
""".strip()

        return [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": user_prompt},
        ]

    def _system_prompt(self) -> str:
        return """
You are the Executor of a coding agent.

Your job:
- Complete one plan step at a time.
- Use tools to inspect, modify, and validate the repository.
- Be careful and grounded.
- Never claim code was changed unless a tool successfully changed it.
- Never mark validation as passed unless tests or syntax checks pass.

Tool-call output format:
Return only JSON when calling a tool:
{
  "tool_name": "read_file",
  "arguments": {
    "path": "core/executor.py"
  }
}

If no more tool call is needed, return a concise natural language result.
""".strip()

    def _tool_descriptions(self) -> str:
        if not self.tools:
            return "No tools are currently registered."

        lines = []
        for name, fn in self.tools.items():
            doc = getattr(fn, "__doc__", "") or ""
            lines.append(f"- {name}: {doc.strip()[:300]}")
        return "\n".join(lines)

    def _normalize_llm_response(self, response: Any) -> str:
        if isinstance(response, str):
            return response

        if isinstance(response, dict):
            if "content" in response:
                return str(response["content"])

            if "message" in response and isinstance(response["message"], dict):
                return str(response["message"].get("content", ""))

            if "choices" in response:
                try:
                    return response["choices"][0]["message"]["content"]
                except Exception:
                    return str(response)

        return str(response)

    def _parse_tool_call(self, content: str) -> Optional[Dict[str, Any]]:
        """
        Parse JSON tool call from LLM output.
        """
        content = content.strip()

        try:
            data = json.loads(content)
            if isinstance(data, dict) and "tool_name" in data:
                return data
        except json.JSONDecodeError:
            pass

        match = re.search(r"\{[\s\S]*\}", content)
        if not match:
            return None

        try:
            data = json.loads(match.group(0))
            if isinstance(data, dict) and "tool_name" in data:
                return data
        except json.JSONDecodeError:
            return None

        return None

    def _tool_result_is_enough(self, step: PlanStep, result: ToolResult) -> bool:
        """
        Simple stopping rule.
        Later you can replace this with LLM-based verification.
        """
        if not result.success:
            return False

        task = step.task.lower()

        if result.tool_name in {"list_files", "search_code", "read_file", "retrieve_context"}:
            return True

        if result.tool_name in {"apply_patch", "replace_in_file", "write_file"}:
            return False

        if result.tool_name in {"run_tests", "run_command"}:
            return result.success

        return True

    def _build_final_answer(self, state: AgentState) -> str:
        completed = [s for s in state.plan if s.status == StepStatus.COMPLETED]
        failed = [s for s in state.plan if s.status == StepStatus.FAILED]

        lines = [
            "Agent run finished.",
            "",
            f"Completed steps: {len(completed)}",
            f"Failed steps: {len(failed)}",
            "",
            "Files read:",
            "\n".join(f"- {f}" for f in state.files_read) or "- None",
            "",
            "Files modified:",
            "\n".join(f"- {f}" for f in state.files_modified) or "- None",
        ]

        if failed:
            lines.append("")
            lines.append("Remaining errors:")
            for step in failed:
                lines.append(f"- Step {step.step_id}: {step.error}")

        return "\n".join(lines)

def execute_current_step(self, state: AgentState) -> AgentState:
    current_step = state.get_current_step()

    if current_step is None:
        state.is_finished = True
        state.final_answer = self._build_final_answer(state)
        return state

    current_step.mark_running()

    try:
        if self.client is None:
            result_text = self._fallback_execute_step(current_step, state)
        else:
            result_text = self._llm_execute_step(current_step, state)

        current_step.mark_completed(result_text)
        state.add_history(
            f"Step {current_step.step_id} completed: {current_step.task}\n{result_text}"
        )

    except Exception as exc:
        error = f"{type(exc).__name__}: {str(exc)}\n{traceback.format_exc()}"
        current_step.mark_failed(error)
        state.errors_seen.append(error)
        state.add_history(
            f"Step {current_step.step_id} failed: {current_step.task}\n{error}"
        )

    return state

def _llm_execute_step(self, step: PlanStep, state: AgentState) -> str:
    messages = self._build_messages(step, state)

    final_outputs = []

    for round_idx in range(self.max_tool_rounds):
        response = self.client.chat(messages)
        content = self._normalize_llm_response(response)

        tool_call = self._parse_tool_call(content)

        if tool_call is None:
            final_outputs.append(content)
            break

        tool_name = tool_call.get("tool_name")
        arguments = tool_call.get("arguments", {})

        tool_result = self._execute_tool(tool_name, arguments, state)

        step.tool_results.append(tool_result)
        state.add_tool_result(tool_result)
        self.memory.update_from_tool_result(tool_result)

        messages.append({
            "role": "assistant",
            "content": content,
        })
        messages.append({
            "role": "tool",
            "content": tool_result.to_text(),
        })

        final_outputs.append(tool_result.to_text(max_chars=1500))

        if self._tool_result_is_enough(step, tool_result):
            break

    if not final_outputs:
        return "No output produced."

    return "\n\n".join(final_outputs)

def _fallback_execute_step(self, step: PlanStep, state: AgentState) -> str:
    """
    Rule-based execution before the LLM tool-calling layer is stable.
    """
    outputs = []

    tools_to_try = step.suggested_tools or []

    if not tools_to_try:
        task_lower = step.task.lower()

        if "structure" in task_lower or "layout" in task_lower:
            tools_to_try = ["list_files"]
        elif "search" in task_lower:
            tools_to_try = ["search_code"]
        elif "read" in task_lower:
            tools_to_try = ["read_file"]
        elif "test" in task_lower or "validation" in task_lower:
            tools_to_try = ["run_tests"]
        else:
            tools_to_try = ["retrieve_context"]

    for tool_name in tools_to_try:
        if tool_name not in self.tools:
            outputs.append(f"Tool {tool_name} is not available.")
            continue

        arguments = self._build_fallback_arguments(tool_name, step, state)
        tool_result = self._execute_tool(tool_name, arguments, state)

        step.tool_results.append(tool_result)
        state.add_tool_result(tool_result)
        self.memory.update_from_tool_result(tool_result)

        outputs.append(tool_result.to_text())

        if tool_result.success:
            break

    return "\n\n".join(outputs)

def _build_fallback_arguments(
    self,
    tool_name: str,
    step: PlanStep,
    state: AgentState,
) -> Dict[str, Any]:
    if tool_name == "list_files":
        return {
            "directory": ".",
            "max_depth": 3,
        }

    if tool_name == "search_code":
        return {
            "query": state.input_query,
            "include_glob": "*.py",
        }

    if tool_name == "retrieve_context":
        return {
            "query": f"{state.input_query}\nCurrent step: {step.task}",
            "top_k": 6,
        }

    if tool_name == "run_tests":
        return {
            "test_path": None,
            "timeout": 60,
        }

    if tool_name == "read_file":
        # If fallback does not know a file, try main.py first.
        return {
            "path": "main.py",
            "start_line": None,
            "end_line": None,
        }

    return {}

def _execute_tool(
    self,
    tool_name: str,
    arguments: Dict[str, Any],
    state: AgentState,
) -> ToolResult:
    if tool_name not in self.tools:
        return ToolResult(
            tool_name=tool_name or "unknown",
            success=False,
            output="",
            error=f"Tool not found: {tool_name}",
        )

    tool_fn = self.tools[tool_name]

    try:
        result = tool_fn(state=state, **arguments)

        if isinstance(result, ToolResult):
            return result

        if isinstance(result, dict):
            return ToolResult(
                tool_name=tool_name,
                success=bool(result.get("success", True)),
                output=str(result.get("output", "")),
                error=result.get("error"),
                metadata=result.get("metadata", {}),
            )

        return ToolResult(
            tool_name=tool_name,
            success=True,
            output=str(result),
        )

    except Exception as exc:
        return ToolResult(
            tool_name=tool_name,
            success=False,
            output="",
            error=f"{type(exc).__name__}: {str(exc)}",
        )

    def _build_messages(self, step: PlanStep, state: AgentState) -> List[Dict[str, str]]:
        system_prompt = self._system_prompt()

        user_prompt = f"""
User request:
{state.input_query}

Current plan:
{state.plan_summary()}

Current step:
Step {step.step_id}: {step.task}

Expected output:
{step.expected_output}

Suggested tools:
{step.suggested_tools}

Retrieved context:
{state.retrieved_context_text()}

Memory:
{self.memory.get_context()}

Recent tool results:
{state.recent_tool_summary()}

Available tools:
{self._tool_descriptions()}

Instructions:
- Decide whether you need to call a tool.
- If you need a tool, return only JSON with this schema:
  {{
    "tool_name": "tool_name_here",
    "arguments": {{
      "key": "value"
    }}
  }}
- If the step is complete, return a concise final message.
- Do not invent file contents.
- Read files before editing them.
- Run validation after applying code changes.
""".strip()

        return [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": user_prompt},
        ]

def _tool_descriptions(self) -> str:
    if not self.tools:
        return "No tools are currently registered."

    lines = []
    for name, fn in self.tools.items():
        doc = getattr(fn, "__doc__", "") or ""
        lines.append(f"- {name}: {doc.strip()[:300]}")
    return "\n".join(lines)

def _normalize_llm_response(self, response: Any) -> str:
    if isinstance(response, str):
        return response

    if isinstance(response, dict):
        if "content" in response:
            return str(response["content"])

        if "message" in response and isinstance(response["message"], dict):
            return str(response["message"].get("content", ""))

        if "choices" in response:
            try:
                return response["choices"][0]["message"]["content"]
            except Exception:
                return str(response)

    return str(response)

def _parse_tool_call(self, content: str) -> Optional[Dict[str, Any]]:
    """
    Parse JSON tool call from LLM output.
    """
    content = content.strip()

    try:
        data = json.loads(content)
        if isinstance(data, dict) and "tool_name" in data:
            return data
    except json.JSONDecodeError:
        pass

    match = re.search(r"\{[\s\S]*\}", content)
    if not match:
        return None

    try:
        data = json.loads(match.group(0))
        if isinstance(data, dict) and "tool_name" in data:
            return data
    except json.JSONDecodeError:
        return None

    return None

def _tool_result_is_enough(self, step: PlanStep, result: ToolResult) -> bool:
    """
    Simple stopping rule.
    Later you can replace this with LLM-based verification.
    """
    if not result.success:
        return False

    task = step.task.lower()

    if result.tool_name in {"list_files", "search_code", "read_file", "retrieve_context"}:
        return True

    if result.tool_name in {"apply_patch", "replace_in_file", "write_file"}:
        return False

    if result.tool_name in {"run_tests", "run_command"}:
        return result.success

    return True

class ToolResult:
    tool_name: str
    success: bool
    output: str
    error: Optional[str] = None
    metadata: Dict[str, Any] = field(default_factory=dict)
    created_at: float = field(default_factory=time.time)

    def to_text(self, max_chars: int = 3000) -> str:
        status = "SUCCESS" if self.success else "FAILED"
        text = f"[{status}] Tool: {self.tool_name}\n"

        if self.output:
            text += f"Output:\n{self.output}\n"

        if self.error:
            text += f"Error:\n{self.error}\n"

        if self.metadata:
            text += f"Metadata:\n{self.metadata}\n"

        if len(text) > max_chars:
            text = text[:max_chars] + "\n...[truncated]"
        return text

def to_text(self, max_chars: int = 3000) -> str:
    status = "SUCCESS" if self.success else "FAILED"
    text = f"[{status}] Tool: {self.tool_name}\n"

    if self.output:
        text += f"Output:\n{self.output}\n"

    if self.error:
        text += f"Error:\n{self.error}\n"

    if self.metadata:
        text += f"Metadata:\n{self.metadata}\n"

    if len(text) > max_chars:
        text = text[:max_chars] + "\n...[truncated]"
    return text

class PlanStep:
    step_id: int
    task: str
    expected_output: str = ""
    suggested_tools: List[str] = field(default_factory=list)
    status: StepStatus = StepStatus.PENDING
    result: Optional[str] = None
    error: Optional[str] = None
    tool_results: List[ToolResult] = field(default_factory=list)
    retry_count: int = 0

    @property
    def is_completed(self) -> bool:
        return self.status == StepStatus.COMPLETED

    @property
    def is_failed(self) -> bool:
        return self.status == StepStatus.FAILED

    def mark_running(self) -> None:
        self.status = StepStatus.RUNNING

    def mark_completed(self, result: str = "") -> None:
        self.status = StepStatus.COMPLETED
        self.result = result
        self.error = None

    def mark_failed(self, error: str) -> None:
        self.status = StepStatus.FAILED
        self.error = error
        self.retry_count += 1

class AgentState:
    input_query: str
    repo_root: str

    run_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    plan: List[PlanStep] = field(default_factory=list)

    history: List[str] = field(default_factory=list)
    tool_history: List[ToolResult] = field(default_factory=list)

    retrieved_context: List[Dict[str, Any]] = field(default_factory=list)

    files_read: List[str] = field(default_factory=list)
    files_modified: List[str] = field(default_factory=list)

    test_results: List[ToolResult] = field(default_factory=list)
    errors_seen: List[str] = field(default_factory=list)

    is_finished: bool = False
    final_answer: Optional[str] = None

    max_steps: int = 20
    max_retries_per_step: int = 2

    metadata: Dict[str, Any] = field(default_factory=dict)

    def __post_init__(self) -> None:
        self.repo_root = str(Path(self.repo_root).resolve())

    def repo_path(self, relative_path: str = "") -> Path:
        """
        Safely resolve a path inside repo root.
        """
        root = Path(self.repo_root).resolve()
        target = (root / relative_path).resolve()

        if not str(target).startswith(str(root)):
            raise ValueError(f"Unsafe path outside repo root: {relative_path}")

        return target

    def add_plan(self, steps: List[PlanStep]) -> None:
        self.plan = steps

    def get_current_step(self) -> Optional[PlanStep]:
        for step in self.plan:
            if step.status in [StepStatus.PENDING, StepStatus.FAILED]:
                if step.retry_count <= self.max_retries_per_step:
                    return step
        return None

    def add_tool_result(self, result: ToolResult) -> None:
        self.tool_history.append(result)

        if result.tool_name == "read_file" and result.success:
            path = result.metadata.get("path")
            if path and path not in self.files_read:
                self.files_read.append(path)

        if result.tool_name in {"apply_patch", "write_file", "replace_in_file"} and result.success:
            changed_files = result.metadata.get("changed_files", [])
            for file_path in changed_files:
                if file_path not in self.files_modified:
                    self.files_modified.append(file_path)

        if result.tool_name in {"run_tests", "run_command"}:
            self.test_results.append(result)

        if not result.success and result.error:
            self.errors_seen.append(result.error)

    def add_history(self, message: str) -> None:
        self.history.append(message)

    def plan_summary(self) -> str:
        if not self.plan:
            return "No plan has been created yet."

        lines = []
        for step in self.plan:
            lines.append(
                f"{step.step_id}. [{step.status.value}] {step.task}"
            )
            if step.error:
                lines.append(f"   Error: {step.error}")
        return "\n".join(lines)

    def recent_tool_summary(self, limit: int = 5) -> str:
        recent = self.tool_history[-limit:]
        if not recent:
            return "No tool calls yet."
        return "\n\n".join(r.to_text(max_chars=1200) for r in recent)

    def retrieved_context_text(self, max_chunks: int = 6, max_chars_per_chunk: int = 1200) -> str:
        if not self.retrieved_context:
            return "No retrieved context."

        blocks = []
        for item in self.retrieved_context[:max_chunks]:
            path = item.get("file_path", "unknown")
            start = item.get("start_line", "?")
            end = item.get("end_line", "?")
            content = item.get("content", "")

            if len(content) > max_chars_per_chunk:
                content = content[:max_chars_per_chunk] + "\n...[truncated]"

            blocks.append(
                f"File: {path}:{start}-{end}\n"
                f"```python\n{content}\n```"
            )

        return "\n\n".join(blocks)

    def should_stop(self) -> bool:
        if self.is_finished:
            return True

        completed_or_failed = [
            s for s in self.plan
            if s.status in [StepStatus.COMPLETED, StepStatus.FAILED, StepStatus.SKIPPED]
        ]

        if self.plan and len(completed_or_failed) == len(self.plan):
            return True

        if len(self.tool_history) >= self.max_steps:
            return True

        return False

