class CodeChunk:
    chunk_id: str
    file_path: str
    content: str
    chunk_type: str
    symbol_name: Optional[str]
    start_line: int
    end_line: int
    language: str
    metadata: Dict[str, Any]

    def to_dict(self) -> Dict[str, Any]:
        return asdict(self)

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> "CodeChunk":
        return cls(**data)

def save(self) -> None:
    if self.index is None:
        raise ValueError("No FAISS index to save.")

    self.index_dir.mkdir(parents=True, exist_ok=True)

    faiss.write_index(self.index, str(self.index_path))

    metadata = {
        "repo_root": str(self.repo_root),
        "embedding_model": self.embedder.model_name,
        "embedding_dim": self.embedder.embedding_dim,
        "num_chunks": len(self.chunks),
        "chunks": [chunk.to_dict() for chunk in self.chunks],
    }

    self.metadata_path.write_text(
        json.dumps(metadata, indent=2, ensure_ascii=False),
        encoding="utf-8",
    )

def load(self) -> Tuple[Any, List[CodeChunk]]:
    if not self.index_path.exists():
        raise FileNotFoundError(f"Missing FAISS index: {self.index_path}")

    if not self.metadata_path.exists():
        raise FileNotFoundError(f"Missing metadata file: {self.metadata_path}")

    self.index = faiss.read_index(str(self.index_path))

    data = json.loads(self.metadata_path.read_text(encoding="utf-8"))
    self.chunks = [CodeChunk.from_dict(item) for item in data["chunks"]]

    return self.index, self.chunks

def _collect_chunks(self) -> List[CodeChunk]:
    chunks: List[CodeChunk] = []

    for file_path in self.repo_root.rglob("*"):
        if not file_path.is_file():
            continue

        rel_path = file_path.relative_to(self.repo_root)

        if self._should_ignore(rel_path):
            continue

        if file_path.suffix.lower() not in SUPPORTED_EXTENSIONS:
            continue

        if self._too_large(file_path):
            continue

        try:
            content = file_path.read_text(encoding="utf-8", errors="replace")
        except Exception:
            continue

        if not content.strip():
            continue

        if file_path.suffix.lower() == ".py":
            file_chunks = self._chunk_python_file(rel_path, content)
        else:
            file_chunks = self._chunk_text_file(rel_path, content)

        chunks.extend(file_chunks)

    return chunks

def _chunk_python_file(self, rel_path: Path, content: str) -> List[CodeChunk]:
    """
    Chunk Python file by class/function when possible.
    Also include import/module-level chunk.
    """
    lines = content.splitlines()
    chunks: List[CodeChunk] = []

    try:
        tree = ast.parse(content)
    except SyntaxError:
        return self._chunk_text_file(rel_path, content, language="python")

    # Module import chunk.
    import_lines = []
    for node in tree.body:
        if isinstance(node, (ast.Import, ast.ImportFrom)):
            start = getattr(node, "lineno", 1)
            end = getattr(node, "end_lineno", start)
            import_lines.extend(lines[start - 1:end])

    if import_lines:
        import_content = "\n".join(import_lines)
        chunks.append(
            self._make_chunk(
                file_path=str(rel_path),
                content=import_content,
                chunk_type="imports",
                symbol_name=None,
                start_line=1,
                end_line=max(1, len(import_lines)),
                language="python",
                metadata={"kind": "imports"},
            )
        )

    symbol_nodes = []

    for node in tree.body:
        if isinstance(node, (ast.ClassDef, ast.FunctionDef, ast.AsyncFunctionDef)):
            symbol_nodes.append(node)

    for node in symbol_nodes:
        start = getattr(node, "lineno", 1)
        end = getattr(node, "end_lineno", start)

        symbol_content = "\n".join(lines[start - 1:end])
        symbol_name = getattr(node, "name", None)

        if isinstance(node, ast.ClassDef):
            chunk_type = "class"
        elif isinstance(node, ast.AsyncFunctionDef):
            chunk_type = "async_function"
        else:
            chunk_type = "function"

        chunks.append(
            self._make_chunk(
                file_path=str(rel_path),
                content=symbol_content,
                chunk_type=chunk_type,
                symbol_name=symbol_name,
                start_line=start,
                end_line=end,
                language="python",
                metadata={
                    "kind": chunk_type,
                    "symbol_name": symbol_name,
                },
            )
        )

        # For class methods, also create method-level chunks.
        if isinstance(node, ast.ClassDef):
            for child in node.body:
                if isinstance(child, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    m_start = getattr(child, "lineno", start)
                    m_end = getattr(child, "end_lineno", m_start)
                    method_content = "\n".join(lines[m_start - 1:m_end])
                    method_name = f"{node.name}.{child.name}"

                    chunks.append(
                        self._make_chunk(
                            file_path=str(rel_path),
                            content=method_content,
                            chunk_type="method",
                            symbol_name=method_name,
                            start_line=m_start,
                            end_line=m_end,
                            language="python",
                            metadata={
                                "kind": "method",
                                "class_name": node.name,
                                "method_name": child.name,
                                "symbol_name": method_name,
                            },
                        )
                    )

    # Fallback: if there are no functions/classes, chunk whole file.
    if not chunks:
        chunks = self._chunk_text_file(rel_path, content, language="python")

    return chunks

def _should_ignore(self, rel_path: Path) -> bool:
    parts = set(rel_path.parts)

    if parts.intersection(IGNORED_DIRS):
        return True

    if rel_path.parts and rel_path.parts[0] == ".agent_index":
        return True

    return False

def _too_large(self, file_path: Path) -> bool:
    try:
        size_kb = file_path.stat().st_size / 1024
        return size_kb > self.max_file_size_kb
    except OSError:
        return True

def load_or_build(self, force_rebuild: bool = False) -> None:
    index_path = self.repo_root / self.index_dir / "index.faiss"
    metadata_path = self.repo_root / self.index_dir / "metadata.json"

    if not force_rebuild and index_path.exists() and metadata_path.exists():
        self.index, self.chunks = self.indexer.load()
    else:
        self.index, self.chunks = self.indexer.build(force_rebuild=True)

def _merge_results(
    self,
    vector_results: List[Dict[str, Any]],
    keyword_results: List[Dict[str, Any]],
) -> List[Dict[str, Any]]:
    """
    Merge vector and keyword candidates by chunk_id.
    """
    merged: Dict[str, Dict[str, Any]] = {}

    for item in vector_results:
        chunk_id = item["chunk_id"]
        merged[chunk_id] = dict(item)

    for item in keyword_results:
        chunk_id = item["chunk_id"]

        if chunk_id not in merged:
            merged[chunk_id] = dict(item)
        else:
            existing = merged[chunk_id]
            existing["source"] = "hybrid"
            existing["keyword_score"] = item.get("keyword_score", 0.0)
            existing["matched_terms"] = item.get("matched_terms", [])
            existing["score"] = max(
                float(existing.get("score", 0.0)),
                float(item.get("score", 0.0)),
            )

    return list(merged.values())

def _chunk_search_text(self, chunk: CodeChunk) -> str:
    return (
        f"{chunk.file_path}\n"
        f"{chunk.symbol_name or ''}\n"
        f"{chunk.chunk_type}\n"
        f"{chunk.language}\n"
        f"{chunk.content}"
    )

def _tokenize(self, text: str) -> List[str]:
    if not text:
        return []

    # Split camelCase / snake_case / normal text roughly.
    text = re.sub(r"([a-z])([A-Z])", r"\1 \2", text)
    raw_tokens = re.findall(r"[A-Za-z_][A-Za-z0-9_]*|[0-9]+", text.lower())

    tokens = []
    for tok in raw_tokens:
        parts = tok.split("_")
        tokens.extend([p for p in parts if p])

    stopwords = {
        "the", "a", "an", "to", "of", "and", "or", "in", "on",
        "for", "with", "is", "are", "be", "this", "that", "it",
    }

    return [t for t in tokens if t not in stopwords and len(t) > 1]

def _keyword_score(
    self,
    query_terms: List[str],
    doc_tokens: List[str],
    raw_text: str,
) -> Dict[str, Any]:
    doc_token_set = set(doc_tokens)
    matched_terms = []

    score = 0.0

    for term in query_terms:
        if term in doc_token_set:
            matched_terms.append(term)

            tf = doc_tokens.count(term)
            score += 1.0 + math.log(1 + tf)

        # Extra bonus for exact raw substring.
        if term in raw_text.lower():
            score += 0.2

    normalized = score / max(1, len(query_terms))

    return {
        "score": normalized,
        "matched_terms": matched_terms,
    }

def _path_relevance_bonus(
    self,
    query: str,
    file_path: str,
    symbol_name: Optional[str],
) -> float:
    query_lower = query.lower()
    file_lower = file_path.lower()
    symbol_lower = (symbol_name or "").lower()

    bonus = 0.0

    important_terms = self._tokenize(query_lower)

    for term in important_terms:
        if term in file_lower:
            bonus += 0.5
        if term in symbol_lower:
            bonus += 0.5

    return min(bonus, 1.0)

class CodeEmbedder:
    """
    Embedding wrapper for code/document chunks.

    Default model:
    - sentence-transformers/all-MiniLM-L6-v2

    Later you can switch to:
    - BAAI/bge-small-en-v1.5
    - mixedbread-ai/mxbai-embed-large-v1
    - nomic-ai/nomic-embed-text-v1.5
    """

    def __init__(
        self,
        model_name: str = "sentence-transformers/all-MiniLM-L6-v2",
        normalize: bool = True,
    ):
        self.model_name = model_name
        self.normalize = normalize
        self.model = None
        self.embedding_dim = None

        self._load_model()

    def _load_model(self) -> None:
        try:
            from sentence_transformers import SentenceTransformer
        except ImportError as exc:
            raise ImportError(
                "sentence-transformers is not installed. "
                "Run: pip install sentence-transformers"
            ) from exc

        self.model = SentenceTransformer(self.model_name)

        # Detect dimension using a small dummy embedding.
        dummy = self.model.encode(
            ["dimension check"],
            convert_to_numpy=True,
            normalize_embeddings=self.normalize,
        )
        self.embedding_dim = int(dummy.shape[1])

    def embed_texts(self, texts: List[str], batch_size: int = 32) -> np.ndarray:
        """
        Embed multiple text chunks.
        """
        if not texts:
            return np.empty((0, self.embedding_dim), dtype="float32")

        embeddings = self.model.encode(
            texts,
            batch_size=batch_size,
            convert_to_numpy=True,
