class EvalError(Exception):
    """Error raised during expression evaluation."""
    pass

def eval_expr(expr: str) -> float:
    """
    Evaluate a simple math expression and return the result.
    """
    expr = expr.replace(" ", "")
    if not expr:
        raise EvalError("empty expression")

    tokens = tokenize(expr)
    return evaluate(tokens)

def tokenize(expr: str) -> list[Token]:
    tokens = []
    i = 0

    while i < len(expr):
        ch = expr[i]

        if ch.isdigit() or ch == '.':
            # Parse number
            j = i
            while j < len(expr) and (expr[j].isdigit() or expr[j] == '.'):
                j += 1
            num_str = expr[i:j]
            try:
                num = float(num_str)
            except ValueError:
                raise EvalError(f"invalid number: {num_str}")
            tokens.append(Token(is_number=True, number=num))
            i = j
        elif ch in "+-*/":
            tokens.append(Token(is_number=False, operator=ch))
            i += 1
        else:
            raise EvalError(f"invalid character: {ch}")

    return tokens

def evaluate(tokens: list[Token]) -> float:
    if not tokens:
        raise EvalError("no tokens to evaluate")
    if not tokens[0].is_number:
        raise EvalError("expression must start with a number")

    # First pass: handle * and /
    new_tokens = [tokens[0]]
    i = 1
    while i < len(tokens):
        op = tokens[i]
        if op.is_number:
            raise EvalError(f"expected operator at position {i}")
        if i + 1 >= len(tokens):
            raise EvalError("missing number after operator")
        num = tokens[i + 1]
        if not num.is_number:
            raise EvalError(f"expected number at position {i + 1}")

        if op.operator in ('*', '/'):
            prev_num = new_tokens.pop()
            if op.operator == '*':
                result = prev_num.number * num.number
            else:
                if num.number == 0:
                    raise EvalError("division by zero")
                result = prev_num.number / num.number
            new_tokens.append(Token(is_number=True, number=result))
        else:
            new_tokens.append(op)
            new_tokens.append(num)
        i += 2

    # Second pass: handle + and -
    result = new_tokens[0].number
    i = 1
    while i < len(new_tokens):
        op = new_tokens[i]
        num = new_tokens[i + 1]
        if op.operator == '+':
            result += num.number
        elif op.operator == '-':
            result -= num.number
        i += 2
    return result

def main():
    if len(sys.argv) != 2:
        print(f"Usage: {sys.argv[0]} <math_expression>", file=sys.stderr)
        print(f'Example: {sys.argv[0]} "2+3"', file=sys.stderr)
        sys.exit(1)

    expr = sys.argv[1]
    try:
        result = eval_expr(expr)
    except EvalError as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)

    print(f"{expr} = {result}")

class TestEvalSimple(unittest.TestCase):
    def test_addition(self):
        self.assertEqual(eval_expr("2+3"), 5)

    def test_subtraction(self):
        self.assertEqual(eval_expr("10-4"), 6)

    def test_multiplication(self):
        self.assertEqual(eval_expr("3*4"), 12)

    def test_division(self):
        self.assertEqual(eval_expr("20/5"), 4)

    def test_precedence(self):
        self.assertEqual(eval_expr("2+3*4"), 14)

